Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it spins up your app in-process with no real network listener, and gives you an `HttpClient` you can hand to the MCP SDK's transport.

### Setup

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
dotnet add package ModelContextProtocol  # the C# MCP SDK
```

### Example test

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using ModelContextProtocol.Client;
using ModelContextProtocol.Protocol.Transport;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>, IAsyncDisposable
{
    private readonly WebApplicationFactory<Program> _factory;
    private IMcpClient? _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _factory = factory;
    }

    private async Task<IMcpClient> CreateClientAsync()
    {
        // WebApplicationFactory gives you an HttpClient that talks
        // to the in-memory TestServer — no ports, no real HTTP.
        var httpClient = _factory.CreateClient();

        var transport = new SseClientTransport(
            new SseClientTransportOptions
            {
                Endpoint = new Uri(httpClient.BaseAddress!, "/mcp"),
                // ^ adjust to your MCP endpoint path
            },
            httpClient   // inject the test HttpClient
        );

        _client = await McpClientFactory.CreateAsync(
            transport,
            new McpClientOptions { ClientInfo = new() { Name = "test" } }
        );

        return _client;
    }

    [Fact]
    public async Task ListTools_ReturnsExpectedTools()
    {
        var client = await CreateClientAsync();

        var tools = await client.ListToolsAsync();

        Assert.Contains(tools, t => t.Name == "my-tool");
    }

    [Fact]
    public async Task CallTool_ReturnsResult()
    {
        var client = await CreateClientAsync();

        var result = await client.CallToolAsync(
            "my-tool",
            new Dictionary<string, object?> { ["input"] = "hello" }
        );

        Assert.False(result.IsError);
        Assert.Contains(result.Content, c => c.Text!.Contains("expected output"));
    }

    public async ValueTask DisposeAsync()
    {
        if (_client is not null)
            await _client.DisposeAsync();
    }
}
```

### Key points

| Concept | Detail |
|---|---|
| **No real server** | `WebApplicationFactory` hosts your app in-memory via `TestServer` |
| **Real MCP protocol** | The SDK's `SseClientTransport` sends actual MCP JSON-RPC over the test `HttpClient` |
| **`Program` class** | Requires your server to expose a `Program` class (top-level statements work if the project has `<InternalsVisibleTo>` for the test project) |
| **Streamable HTTP** | If your server uses the newer Streamable HTTP transport instead of SSE, swap `SseClientTransport` for `StreamableHttpClientTransport` with the same pattern |

### Exposing `Program` to tests

Add this to your **server** project file:

```xml
<ItemGroup>
  <InternalsVisibleTo Include="YourTestProjectName" />
</ItemGroup>
```

This gives you full end-to-end MCP protocol coverage (initialize → list → call → shutdown) entirely in-process.
